using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Build the chat client with automatic function-calling support
// ---------------------------------------------------------------------------
IChatClient innerClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

using IChatClient client = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation()
    .Build();

// ---------------------------------------------------------------------------
// Register tools
// ---------------------------------------------------------------------------
var researchTools = new ResearchTools();

List<AITool> tools =
[
    AIFunctionFactory.Create(researchTools.WebSearch),
    AIFunctionFactory.Create(researchTools.SaveNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
];

// ---------------------------------------------------------------------------
// Conversation setup
// ---------------------------------------------------------------------------
const string SystemPrompt = """
    You are a research agent. When the user gives you a topic, follow this workflow:

    1. Break the topic into 3-5 focused search queries.
    2. Call WebSearch for each query.
    3. After each search, call SaveNote with the key facts you found.
    4. Once all searches are done, call GetNotes to review everything.
    5. Produce a well-structured summary with sections and citations.

    Always search before summarizing. Be thorough and cite your sources.
    """;

List<ChatMessage> messages = [new(ChatRole.System, SystemPrompt)];

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        🔬  AI Research Agent  🔬        ║");
Console.WriteLine("╠══════════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or 'quit'.  ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic ▸ ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    // Reset tools state for each new research session
    researchTools.ClearNotes();

    messages.Add(new(ChatRole.User, $"Research this topic and provide a comprehensive summary: {topic}"));

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.Yellow;
    Console.WriteLine($"🔍  Researching: {topic}");
    Console.ResetColor();
    Console.WriteLine();

    // Stream the response so the user sees incremental output
    var responseBuilder = new StringBuilder();
    bool headerPrinted = false;

    await foreach (var update in client.GetStreamingResponseAsync(messages, new() { Tools = tools }))
    {
        if (update.Text is { Length: > 0 } text)
        {
            if (!headerPrinted)
            {
                Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
                Console.ForegroundColor = ConsoleColor.Green;
                Console.WriteLine("📋  Research Summary");
                Console.ResetColor();
                Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
                headerPrinted = true;
            }
            Console.Write(text);
            responseBuilder.Append(text);
        }
    }

    Console.WriteLine();
    Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    Console.WriteLine();

    // Keep the assistant reply in context for follow-up research
    messages.Add(new(ChatRole.Assistant, responseBuilder.ToString()));
