Console.WriteLine("Goodbye! 👋");

// ===========================================================================
// Tool definitions
// ===========================================================================
public sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _http = new();

    public void ClearNotes() => _notes.Clear();

    [Description("Search the web for information on a topic. Returns relevant text snippets.")]
    public async Task<string> WebSearch(
        [Description("The search query to look up")] string query)
    {
        Console.ForegroundColor = ConsoleColor.DarkGray;
        Console.WriteLine($"  🌐  Searching: \"{query}\"");
        Console.ResetColor();

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&t=ResearchAgent";
            var json = await _http.GetStringAsync(url);
            var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            if (root.TryGetProperty("Abstract", out var abs) &&
                abs.GetString() is { Length: > 0 } abstractText)
            {
                var source = root.TryGetProperty("AbstractSource", out var src)
                    ? src.GetString() : "unknown";
                results.Add($"[{source}] {abstractText}");
            }

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        text.GetString() is { Length: > 0 } snippet)
                    {
                        var firstUrl = topic.TryGetProperty("FirstURL", out var u)
                            ? u.GetString() : null;
                        results.Add(firstUrl is not null
                            ? $"{snippet} (source: {firstUrl})"
                            : snippet);
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : $"No detailed results for \"{query}\". Try rephrasing.";
        }
        catch (Exception ex)
        {
            return $"Search error: {ex.Message}";
        }
    }

    [Description("Save an important research finding as a note for later use in the summary.")]
    public string SaveNote(
        [Description("The note to save — include key facts and the source")] string note)
    {
        _notes.Add(note);

        Console.ForegroundColor = ConsoleColor.DarkGray;
        Console.WriteLine($"  📝  Note saved  (total: {_notes.Count})");
        Console.ResetColor();

        return $"Saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all previously saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        Console.ForegroundColor = ConsoleColor.DarkGray;
        Console.WriteLine($"  📖  Retrieving {_notes.Count} note(s)");
        Console.ResetColor();

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
            sb.AppendLine($"[{i + 1}] {_notes[i]}");
        return sb.ToString();
    }
}

